import Vue from 'vue';
import VueRouter from 'vue-router';

import MainView from '../layouts/MainView.vue';

import HomeIndex from '../views/Index.vue';
import AboutIndex from '../views/a/Index.vue';
import WorksIndex from '../views/w/Index.vue';
import SkillsIndex from '../views/s/Index.vue';
import ContactIndex from '../views/c/Index.vue';

import Error404 from '../views/Error404.vue';


Vue.use(VueRouter);
const routes = [
	{ path: '', component: MainView,
		children: [
			{ path: '', component: HomeIndex, name: 'home-index', meta: { transitionb: { ec: 'slideInLeft', lc: 'slideOutRight'}, transitionf: { ec: 'slideInRight', lc: 'slideOutLeft' }, ix: 0 } },
			{ path: 'about', component: AboutIndex, name: 'about-index', meta: { transitionb: { ec: 'slideInLeft', lc: 'slideOutRight'}, transitionf: { ec: 'slideInRight', lc: 'slideOutLeft' }, ix: 1 } },
			{ path: 'works', component: WorksIndex, name: 'works-index', meta: { transitionb: { ec: 'slideInLeft', lc: 'slideOutRight'}, transitionf: { ec: 'slideInRight', lc: 'slideOutLeft' }, ix: 2 } },
			{ path: 'skills', component: SkillsIndex, name: 'skills-index', meta: { transitionb: { ec: 'slideInLeft', lc: 'slideOutRight'}, transitionf: { ec: 'slideInRight', lc: 'slideOutLeft' }, ix: 3 } },
			{ path: 'contact', component: ContactIndex, name: 'contact-index', meta: { transitionb: { ec: 'slideInLeft', lc: 'slideOutRight'}, transitionf: { ec: 'slideInRight', lc: 'slideOutLeft' }, ix: 4 } }
		]
	},
	{ path: '*', component: Error404, name: 'error-404' }
];


const router = new VueRouter({
	mode: 'hash',
	base: process.env.BASE_URL,
	routes
});


export default router;
