import axios from 'axios';
import md5 from './md5.js';

import ImageLoader from '@/components/ImageLoader.vue';
import HeadIcon from '@/components/HeadIcon.vue';
import HeadBack from '@/components/HeadBack.vue';
import VIcon from 'vue-awesome/components/Icon.vue';

export default {
	install(Vue) {
		Vue.mixin({
			data() {
				return {
					get mapDimension() {
						return [1654, 837];
					},
					get mapRectangle() {
						return { lat_x: 7.999376, lng_x: 124.251704, lat_y: 7.991375, lng_y: 124.267508 };
					}
				}
			},
			methods: {
				$storageGet(key, type) {
					var ttype = type || 'local';
					var value = ttype === 'local' ? window.localStorage.getItem(key) : window.sessionStorage.getItem(key)
					return value && JSON.parse(value)
				},
				$storageSet(key, value, type) {
					var ttype = type || 'local';
					if (ttype === 'local')
						window.localStorage.setItem(key, JSON.stringify(value));
					else if(ttype === 'session')
						window.sessionStorage.setItem(key, JSON.stringify(value));
				},
				$storageDel(key, type) {
					var ttype = type || 'local';
					if (ttype === 'local')
						window.localStorage.removeItem(key);
					else if(ttype === 'session')
						window.sessionStorage.removeItem(key);
				},
				$sleep(milliseconds) {
					return new Promise(resolve => window.setTimeout(resolve, milliseconds));
				},
				$randomKeyGenerator() {
					return Math.floor(Math.random() * 1000000);
				},
				$md5KeyGenerator(text) {
					return md5(text);
				},
			},
			mounted() {
				
			}
		});

		Vue.filter('currency', function(value) {
			if (typeof value !== "number") {
				return value;
			}
			const formatter = new Intl.NumberFormat('en-PH', {
				style: 'currency',
				currency: 'PHP',
				symbol: '₱',
				minimumFractionDigits: 2
			});
			return formatter.format(value);
		});

		Vue.filter('currencyNoSymbol', function(value) {
			return value.replace('₱', '');
		});

		Vue.filter('lowercase', function(value) {
			return value.toLowerCase();
		});

		Vue.filter('uppercase', function(value) {
			return value.toUpperCase();
		});

		Vue.filter('getDate', function(value) {
			var d = new Date(value);
			return d.getFullYear() +'-'+ Number.parseInt(d.getMonth()+1) +'-'+ d.getDate();
		});

		/**Vue.directive('currency', {
			twoWay: true,
			bind: function () {
				this.handler = function() {
					const formatter = new Intl.NumberFormat('en-PH', {
						style: 'currency',
						currency: 'PHP',
						minimumFractionDigits: 2
					});
					const value = formatter.format(this.el.value).replace('₱', '');
					this.set(value);
				}.bind(this);
				this.el.addEventListener('input', this.handler);
			},
			unbind: function() {
				this.el.removeEventListener('input', this.handler);
			}
		}); **/

		Vue.component('image-loader', ImageLoader);
		Vue.component('head-icon', HeadIcon);
		Vue.component('head-back', HeadBack);
		Vue.component('v-icon', VIcon);

		Vue.prototype.$http = axios.create({ baseURL: Vue.prototype.apiBaseURL, timeout: 10000 });
		Vue.prototype.$http.interceptors.request.use(function (config) {
				const api_token = window.localStorage.getItem("api_token") || "0";
				config.headers.common["Authorization"] = "Token "+ JSON.parse(api_token);
				return config;
			}, function (error) {
				return Promise.reject(error);
		});
	}
};